/**
 * 性能与内存信息模块
 * 采集浏览器性能和内存的稳定特征（排除时间相关动态数据）。
 */
/**
 * 获取 JS 堆内存信息（仅 Chromium 支持 `performance.memory`）
 * @returns 堆大小限制和总堆大小，或设备内存
 */
export declare const getMemoryInfo: () => Record<string, unknown>;
/**
 * 获取稳定的性能特征指纹（排除时间戳等动态数据）
 * @returns 导航类型和 CPU 核心数
 */
export declare const getPerformanceFingerprint: () => Record<string, unknown>;
